#include <stdio.h>
#include <stdlib.h>

int cmp_desc(const void *a, const void *b) {
    int x = *(int *)b - *(int *)a; // descending
    return x;
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int *arr = (int *)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &arr[i]);
        qsort(arr, N, sizeof(int), cmp_desc);
        long long ans = 0;
        for (int i = 0; i < N; ++i) {
            long long cur = (long long)(i + 1) * arr[i];
            if (cur > ans) ans = cur;
        }
        printf("%lld\n", ans);
        free(arr);
    }
    return 0;
}

