        sort(a.rbegin(), a.rend());
        long long ans=0;
        for(int i=0;i<N;++i){
            long long cur = (long long)(i+1)*a[i];
            ans = max(ans, cur);
        }
        cout<<ans<<"\n";
    }
    return 0;
