const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
const T = input[idx++];
let outputs = [];
for (let t = 0; t < T; ++t) {
  const N = input[idx++];
  const arr = input.slice(idx, idx + N);
  idx += N;
  arr.sort((a, b) => b - a); // descending
  let ans = 0;
  for (let i = 0; i < N; ++i) {
    const cur = (i + 1) * arr[i];
    if (cur > ans) ans = cur;
  }
  outputs.push(String(ans));
}
console.log(outputs.join('\n'));

